using System;
using System.Collections.Generic;
using System.Linq;

namespace DWD.Data
{
    [System.Serializable]
    public class CarData
    {
        public string Id;
        public CarTier Tier;
        public string Make;
        public float Aesthetic;
        public List<ComponentCondition> Components;
        public List<ComponentType> HiddenFlaws;
        public WarrantyType WarrantyType;
        public int WarrantyDurationDays;
        public int WarrantyExpiresOnDay;
        public int PurchasePrice;
        public int MarketValue;
        public int SoldPrice;
        public int SoldOnDay;
        public int ListedPrice;
        public bool IsListed;
        public bool IsSold;

        public float OverallReliability =>
            Components.Count > 0 ? Components.Min(c => c.Reliability) : 0f;

        public float OverallMechanical =>
            Components.Count > 0 ? Components.Average(c => c.Mechanical) : 0f;

        public static CarData CreateDefault(CarTier tier, string make, int purchasePrice, int marketValue)
        {
            return new CarData
            {
                Id = Guid.NewGuid().ToString(),
                Tier = tier,
                Make = make,
                Aesthetic = 0.5f,
                Components = new List<ComponentCondition>
                {
                    new ComponentCondition(ComponentType.Engine, 0.5f, 0f),
                    new ComponentCondition(ComponentType.Transmission, 0.5f, 0f),
                    new ComponentCondition(ComponentType.Brakes, 0.5f, 0f),
                    new ComponentCondition(ComponentType.Body, 0.5f, 0f),
                    new ComponentCondition(ComponentType.Interior, 0.5f, 0f),
                },
                HiddenFlaws = new List<ComponentType>(),
                PurchasePrice = purchasePrice,
                MarketValue = marketValue,
            };
        }
    }
