    [System.Serializable]
    public class LoanRecord
    {
        public int Principal;
        public float APR;
        public int TermDays;
        public int Balance;
        public int DueOnDay;
        public int MissedPayments;

        public float DailyInterest => Principal * APR / 365f;

        public LoanRecord(int principal, float apr, int termDays)
        {
            Principal = principal;
            APR = apr;
            TermDays = termDays;
            Balance = principal;
            MissedPayments = 0;
        }

        public void AccrueDaily()
        {
            Balance += UnityEngine.Mathf.CeilToInt(DailyInterest);
        }
    }
}

