// DWD/Assets/Scripts/Data/BalancingConfig.cs
using UnityEngine;

namespace DWD.Data
{
    public enum ToolkitLevel { None, Basic, Pro }

    [CreateAssetMenu(fileName = "BalancingConfig", menuName = "DWD/Balancing Config")]
    public class BalancingConfig : ScriptableObject
    {
        [Header("Repair")]
        public float FumbleRateBase = 0.15f;
        public float FumbleRateBasicToolkit = 0.10f;
        public float FumbleRateProToolkit = 0.05f;
        public float FumbleConditionPenalty = 0.15f;
        public float FumbleCostMultiplier = 1.5f;
        public float SelfRepairReliabilityMin = 0.70f;
        public float SelfRepairReliabilityMax = 0.85f;
        public float CertifiedShopReliability = 0.95f;
        public float JuniorMechanicReliability = 0.75f;
        public int CertifiedShopCostPerJob = 200;

        [Header("Detailing")]
        public float DetailPassOne = 0.15f;
        public float DetailPassTwo = 0.05f;
        public float DetailPassThree = 0.02f;

        [Header("Warranty")]
        public int WarrantyRollInterval = 7;
        public int ThirdPartyBasicCost = 150;
        public int ThirdPartyBasicDays = 30;
        public int ThirdPartyPremiumCost = 400;
        public int ThirdPartyPremiumDays = 60;
        public int SelfFundedStandardDays = 30;
        public int SelfFundedPremiumDays = 60;

        [Header("Legal")]
        public float LegalDebtMultiplierWarning = 1.5f;
        public float LegalDebtMultiplierLawsuit = 2.0f;
        public int WarningFreezeDays = 7;
        public int WarningDeadlineDays = 14;
        public int LawsuitFreezeDays = 14;
        public int LawsuitDeadlineDays = 21;
        public float LawsuitRepPenalty = -10f;

        [Header("Economy")]
        public int StartingCash = 2500;
        public float DayLengthSeconds = 60f;
        public float BuyerOfferMin = 0.85f;
        public float BuyerOfferMax = 1.10f;
        public float OverpricedThreshold = 1.20f;
        public int BankruptcyDays = 30;

        [Header("REP")]
        public float StartingRep = 25f;
        public float RepBlacklistThreshold = 10f;
        public float RepExecutiveThreshold = 40f;
        public float RepContractThreshold = 60f;
        public float RepCollectorThreshold = 80f;
        public float RepInterestDiscountThreshold = 70f;
        public float RepInterestDiscount = 0.02f;
        public float RepCleanSale = 3f;
        public float RepWarrantyClaimPaid = -1f;
        public float RepWarrantyClaimUnpaid = -5f;
        public float RepMissedLoanPayment = -2f;

        [Header("Loans")]
        public int StarterLoanPrincipal = 2000;
        public float StarterLoanAPR = 0.12f;
        public int StarterLoanTerm = 30;
        public int YardLoanPrincipal = 10000;
        public float YardLoanAPR = 0.10f;
        public int YardLoanTerm = 60;
        public int ShowroomLoanPrincipal = 50000;
        public float ShowroomLoanAPR = 0.08f;
        public int ShowroomLoanTerm = 90;
        public float LatePaymentFeeMultiplier = 1.5f;

        [Header("Stage Capacity")]
        public int DrivewayCapacity = 1;
        public int YardCapacity = 5;
        public int DealershipCapacity = 12;

        public float GetFumbleRate(ToolkitLevel toolkit)
        {
            return toolkit switch
            {
                ToolkitLevel.Basic => FumbleRateBasicToolkit,
                ToolkitLevel.Pro => FumbleRateProToolkit,
                _ => FumbleRateBase
            };
        }

        public float GetRepairReliability(RepairMethod method, ToolkitLevel toolkit)
        {
            return method switch
            {
                RepairMethod.CertifiedShop => CertifiedShopReliability,
                RepairMethod.JuniorMechanic => JuniorMechanicReliability,
                _ => Mathf.Lerp(SelfRepairReliabilityMin, SelfRepairReliabilityMax,
                    (float)toolkit / (float)ToolkitLevel.Pro)
            };
        }

        public int GetStageCapacity(GameStage stage)
        {
            return stage switch
            {
                GameStage.Yard => YardCapacity,
                GameStage.Dealership => DealershipCapacity,
                _ => DrivewayCapacity
            };
        }
    }
}
```

