// DWD/Assets/Scripts/Core/LegalEventManager.cs
using System;
using DWD.Data;
using UnityEngine;

namespace DWD.Core
{
    public class LegalEventManager : MonoBehaviour
    {
        public LegalEvent ActiveEvent { get; private set; }
        public LegalSeverity? CurrentSeverity => ActiveEvent?.Severity;

        private BalancingConfig _config;
        private int _salesFreezeUntilDay;

        public event Action<LegalEvent> OnLegalEvent;

        public void Initialize(BalancingConfig config)
        {
            _config = config;
            ActiveEvent = null;
            _salesFreezeUntilDay = 0;
        }

        public void HandleUnpaidClaim(int claimCost, int currentDay)
        {
            if (ActiveEvent == null || ActiveEvent.Resolved)
            {
                // First unpaid: Warning
                ActiveEvent = new LegalEvent
                {
                    Severity = LegalSeverity.Warning,
                    TriggeredOnDay = currentDay,
                    DeadlineDay = currentDay + _config.WarningDeadlineDays,
                    DebtAmount = Mathf.CeilToInt(claimCost * _config.LegalDebtMultiplierWarning),
                    Resolved = false
                };
                _salesFreezeUntilDay = currentDay + _config.WarningFreezeDays;
            }
            else
            {
                // Escalate to Lawsuit
                ActiveEvent = new LegalEvent
                {
                    Severity = LegalSeverity.Lawsuit,
                    TriggeredOnDay = currentDay,
                    DeadlineDay = currentDay + _config.LawsuitDeadlineDays,
                    DebtAmount = Mathf.CeilToInt(claimCost * _config.LegalDebtMultiplierLawsuit),
                    Resolved = false
                };
                _salesFreezeUntilDay = currentDay + _config.LawsuitFreezeDays;
            }

            OnLegalEvent?.Invoke(ActiveEvent);
        }

        public bool IsSalesFrozen(int currentDay) => currentDay < _salesFreezeUntilDay;

        public bool IsBlacklisted(int currentDay)
        {
            return ActiveEvent != null
                && ActiveEvent.Severity == LegalSeverity.Lawsuit
                && !ActiveEvent.Resolved
                && currentDay > ActiveEvent.DeadlineDay;
        }

        public void ResolveEvent()
        {
            if (ActiveEvent != null)
                ActiveEvent.Resolved = true;
            ActiveEvent = null;
            _salesFreezeUntilDay = 0;
        }
    }
}
