using DWD.Data;
using UnityEngine;

namespace DWD.Core
{
    public static class BuyerGenerator
    {
        public static BuyerOffer TryGenerateOffer(CarData car, float rep, BalancingConfig config, int currentDay)
        {
            if (!car.IsListed) return null;
            if (car.ListedPrice > car.MarketValue * config.OverpricedThreshold) return null;

            // Higher rep = higher chance of offer
            float offerChance = Mathf.Lerp(0.3f, 0.8f, rep / 100f);
            if (Random.value > offerChance) return null;

            // Offer weighted by rep
            float repWeight = Mathf.Lerp(0f, 1f, rep / 100f);
            float offerPercent = Mathf.Lerp(config.BuyerOfferMin, config.BuyerOfferMax, repWeight * Random.value);
            int offerPrice = Mathf.RoundToInt(car.ListedPrice * offerPercent);

            return new BuyerOffer
            {
                CarId = car.Id,
                OfferPrice = offerPrice,
                OfferedOnDay = currentDay
            };
        }
    }
}
