// DWD/Assets/Scripts/Core/EconomyController.cs
using System;
using System.Collections.Generic;
using DWD.Data;
using UnityEngine;

namespace DWD.Core
{
    public class EconomyController : MonoBehaviour
    {
        public int Cash { get; private set; }
        public bool IsBankrupt { get; private set; }
        public List<string> TransactionLog { get; private set; } = new();

        private BalancingConfig _config;
        private int _consecutiveNegativeDays;

        public event Action<int, string> OnCashChanged;

        public void Initialize(BalancingConfig config)
        {
            _config = config;
            Cash = config.StartingCash;
            _consecutiveNegativeDays = 0;
            IsBankrupt = false;
        }

        public void AddCash(int amount, string reason)
        {
            Cash += amount;
            string entry = $"+${amount}: {reason} (Balance: ${Cash})";
            TransactionLog.Add(entry);
            OnCashChanged?.Invoke(Cash, entry);
        }

        public void DeductCash(int amount, string reason)
        {
            Cash -= amount;
            string entry = $"-${amount}: {reason} (Balance: ${Cash})";
            TransactionLog.Add(entry);
            OnCashChanged?.Invoke(Cash, entry);
        }

        public bool CanAfford(int amount) => Cash >= amount;

        public void ProcessDay()
        {
            if (Cash < 0)
            {
                _consecutiveNegativeDays++;
                if (_consecutiveNegativeDays >= _config.BankruptcyDays)
                    IsBankrupt = true;
            }
            else
            {
                _consecutiveNegativeDays = 0;
            }
        }
    }
}
