        public bool IsExecutiveUnlocked => Rep >= _config.RepExecutiveThreshold;
        public bool IsContractsUnlocked => Rep >= _config.RepContractThreshold;
        public bool IsCollectorUnlocked => Rep >= _config.RepCollectorThreshold;
        public bool QualifiesForInterestDiscount => Rep >= _config.RepInterestDiscountThreshold;

        public event Action<float, string> OnRepChanged;

        public void Initialize(BalancingConfig config)
        {
            _config = config;
            Rep = config.StartingRep;
        }

        public void AdjustRep(float amount, string reason)
        {
            Rep = Mathf.Clamp(Rep + amount, 0f, 100f);
            OnRepChanged?.Invoke(Rep, reason);
        }
    }
}
