// DWD/Assets/Scripts/Core/RepairShop.cs
using DWD.Data;
using UnityEngine;

namespace DWD.Core
{
    public struct RepairResult
    {
        public bool Fumbled;
        public int Cost;
        public float NewMechanical;
        public float NewReliability;
        public string Description;
    }

    public static class RepairShop
    {
        private const int BaseRepairCost = 150;

        public static RepairResult AttemptRepair(
            CarData car, ComponentType component, RepairMethod method,
            ToolkitLevel toolkit, BalancingConfig config, float rollOverride = -1f)
        {
            var comp = car.Components.Find(c => c.Type == component);
            float roll = rollOverride >= 0 ? rollOverride : Random.value;
            float fumbleRate = method == RepairMethod.Self ? config.GetFumbleRate(toolkit) : 0.03f;
            bool fumbled = roll < fumbleRate;

            int cost = BaseRepairCost;
            if (method == RepairMethod.CertifiedShop)
                cost += config.CertifiedShopCostPerJob;

            if (fumbled)
            {
                comp.Mechanical = Mathf.Max(0f, comp.Mechanical - config.FumbleConditionPenalty);
                cost = Mathf.CeilToInt(cost * config.FumbleCostMultiplier);
                comp.Reliability = config.GetRepairReliability(method, toolkit) * 0.8f;
            }
            else
            {
                comp.Mechanical = Mathf.Min(1f, comp.Mechanical + (1f - comp.Mechanical) * 0.8f);
                comp.Reliability = config.GetRepairReliability(method, toolkit);
            }

            return new RepairResult
            {
                Fumbled = fumbled,
                Cost = cost,
                NewMechanical = comp.Mechanical,
                NewReliability = comp.Reliability,
                Description = fumbled
                    ? $"FUMBLE repairing {component}! Condition dropped, cost: ${cost}"
                    : $"Repaired {component}. Condition: {comp.Mechanical:F2}, Reliability: {comp.Reliability:F2}, Cost: ${cost}"
            };
        }
    }
}
