// DWD/Assets/Scripts/Core/WarrantyLedger.cs
using System;
using System.Collections.Generic;
using System.Linq;
using DWD.Data;
using UnityEngine;

namespace DWD.Core
{
    public struct WarrantyClaim
    {
        public string CarId;
        public string CarDescription;
        public int RepairCost;
    }

    public class WarrantyLedger : MonoBehaviour
    {
        private List<WarrantyRecord> _warranties = new();
        private BalancingConfig _config;

        public event Action<WarrantyClaim> OnClaimGenerated;

        public void Initialize(BalancingConfig config)
        {
            _config = config;
            _warranties.Clear();
        }

        public void AddWarranty(WarrantyRecord record) => _warranties.Add(record);

        public List<WarrantyRecord> ActiveWarranties(int currentDay) =>
            _warranties.Where(w => w.IsActive(currentDay)).ToList();

        public int TotalExposure(int currentDay) =>
            ActiveWarranties(currentDay)
                .Where(w => w.Type == WarrantyType.SelfFundedStandard || w.Type == WarrantyType.SelfFundedPremium)
                .Sum(w => w.EstimatedClaimCost);

        public List<WarrantyClaim> ProcessDay(int currentDay, float rollOverride = -1f)
        {
            var claims = new List<WarrantyClaim>();
            if (currentDay % _config.WarrantyRollInterval != 0) return claims;

            foreach (var w in ActiveWarranties(currentDay))
            {
                if (w.Type == WarrantyType.ThirdPartyBasic || w.Type == WarrantyType.ThirdPartyPremium)
                    continue;
                if (w.Type == WarrantyType.None)
                    continue;

                float roll = rollOverride >= 0 ? rollOverride : UnityEngine.Random.value;
                if (roll > w.CarReliability)
                {
                    var claim = new WarrantyClaim
                    {
                        CarId = w.CarId,
                        CarDescription = w.CarDescription,
                        RepairCost = w.EstimatedClaimCost
                    };
                    claims.Add(claim);
                    OnClaimGenerated?.Invoke(claim);
                }
            }
            return claims;
        }
    }
}
