// DWD/Assets/Scripts/Core/LoanManager.cs
using System;
using System.Collections.Generic;
using System.Linq;
using DWD.Data;
using UnityEngine;

namespace DWD.Core
{
    public class LoanManager : MonoBehaviour
    {
        public List<LoanRecord> ActiveLoans { get; private set; } = new();
        public int TotalDebt => ActiveLoans.Sum(l => l.Balance);

        private BalancingConfig _config;

        public event Action<string> OnLoanEvent;

        public void Initialize(BalancingConfig config)
        {
            _config = config;
            ActiveLoans.Clear();
        }

        public int TakeStarterLoan(int currentDay)
        {
            var loan = new LoanRecord(_config.StarterLoanPrincipal, _config.StarterLoanAPR, _config.StarterLoanTerm);
            loan.DueOnDay = currentDay + _config.StarterLoanTerm;
            ActiveLoans.Add(loan);
            OnLoanEvent?.Invoke($"Took Starter Loan: ${loan.Principal} at {loan.APR * 100}% APR, due day {loan.DueOnDay}");
            return loan.Principal;
        }

        public int TakeYardLoan(int currentDay)
        {
            var loan = new LoanRecord(_config.YardLoanPrincipal, _config.YardLoanAPR, _config.YardLoanTerm);
            loan.DueOnDay = currentDay + _config.YardLoanTerm;
            ActiveLoans.Add(loan);
            OnLoanEvent?.Invoke($"Took Yard Loan: ${loan.Principal} at {loan.APR * 100}% APR, due day {loan.DueOnDay}");
            return loan.Principal;
        }

        public int TakeShowroomLoan(int currentDay)
        {
            var loan = new LoanRecord(_config.ShowroomLoanPrincipal, _config.ShowroomLoanAPR, _config.ShowroomLoanTerm);
            loan.DueOnDay = currentDay + _config.ShowroomLoanTerm;
            ActiveLoans.Add(loan);
            OnLoanEvent?.Invoke($"Took Showroom Loan: ${loan.Principal} at {loan.APR * 100}% APR, due day {loan.DueOnDay}");
            return loan.Principal;
        }

        public void MakePayment(int loanIndex, int amount)
        {
            if (loanIndex < 0 || loanIndex >= ActiveLoans.Count) return;
            var loan = ActiveLoans[loanIndex];
            loan.Balance -= amount;
            if (loan.Balance <= 0)
            {
                ActiveLoans.RemoveAt(loanIndex);
                OnLoanEvent?.Invoke("Loan fully repaid!");
            }
            else
            {
                OnLoanEvent?.Invoke($"Payment of ${amount}. Remaining: ${loan.Balance}");
            }
        }

        public List<string> ProcessDay(int currentDay, bool qualifiesForDiscount)
        {
            var events = new List<string>();
            foreach (var loan in ActiveLoans)
            {
                float effectiveAPR = qualifiesForDiscount
                    ? Mathf.Max(0, loan.APR - _config.RepInterestDiscount)
                    : loan.APR;
                int interest = Mathf.CeilToInt(loan.Principal * effectiveAPR / 365f);
                loan.Balance += interest;

                if (currentDay > loan.DueOnDay && loan.Balance > 0)
                {
                    loan.MissedPayments++;
                    int fee = Mathf.CeilToInt(interest * _config.LatePaymentFeeMultiplier);
                    loan.Balance += fee;
                    events.Add($"MISSED PAYMENT! Late fee: ${fee}. Total debt: ${loan.Balance}");
                }
            }
            return events;
        }
    }
}
