// DWD/Assets/Scripts/Core/ListingGenerator.cs
using System.Collections.Generic;
using DWD.Data;
using UnityEngine;

namespace DWD.Core
{
    public static class ListingGenerator
    {
        private static readonly string[] BudgetMakes = { "Pixel-Toyota", "Pixel-Honda", "Pixel-Ford", "Pixel-Chevy" };
        private static readonly string[] CommuterMakes = { "Pixel-Mazda", "Pixel-Subaru", "Pixel-Hyundai", "Pixel-Kia" };
        private static readonly string[] ExecutiveMakes = { "Pixel-BMW", "Pixel-Audi", "Pixel-Lexus", "Pixel-Mercedes" };
        private static readonly string[] CollectorMakes = { "Pixel-Porsche", "Pixel-Ferrari", "Pixel-Corvette", "Pixel-Mustang" };

        public static List<CarData> GenerateListings(GameStage stage, float rep, BalancingConfig config)
        {
            var listings = new List<CarData>();
            int count = stage == GameStage.Driveway ? 3 : stage == GameStage.Yard ? 6 : 10;

            for (int i = 0; i < count; i++)
            {
                CarTier tier = PickTier(stage, rep, config);
                listings.Add(GenerateCar(tier));
            }
            return listings;
        }

        private static CarTier PickTier(GameStage stage, float rep, BalancingConfig config)
        {
            if (stage == GameStage.Driveway) return CarTier.Budget;

            float roll = Random.value;
            if (rep >= config.RepCollectorThreshold && roll < 0.1f) return CarTier.Collector;
            if (rep >= config.RepExecutiveThreshold && roll < 0.3f) return CarTier.Executive;
            if (stage >= GameStage.Yard && roll < 0.6f) return CarTier.Commuter;
            return CarTier.Budget;
        }

        private static CarData GenerateCar(CarTier tier)
        {
            string[] makes = tier switch
            {
                CarTier.Commuter => CommuterMakes,
                CarTier.Executive => ExecutiveMakes,
                CarTier.Collector => CollectorMakes,
                _ => BudgetMakes
            };

            (int minPrice, int maxPrice, int margin) = tier switch
            {
                CarTier.Commuter => (2000, 5000, 1500),
                CarTier.Executive => (5000, 15000, 4000),
                CarTier.Collector => (15000, 50000, 10000),
                _ => (800, 2500, 800)
            };

            int purchasePrice = Random.Range(minPrice, maxPrice);
            int marketValue = purchasePrice + Random.Range(margin / 2, margin);
            string make = makes[Random.Range(0, makes.Length)];

            var car = CarData.CreateDefault(tier, make, purchasePrice, marketValue);

            // Randomize condition
            foreach (var comp in car.Components)
                comp.Mechanical = Random.Range(0.2f, 0.7f);
            car.Aesthetic = Random.Range(0.2f, 0.6f);

            // Maybe add hidden flaws
            if (Random.value < 0.3f)
                car.HiddenFlaws.Add(car.Components[Random.Range(0, car.Components.Count)].Type);

            return car;
        }
    }
}

