```csharp
// DWD/Assets/Scripts/Core/GameManager.cs
using System;
using System.Collections.Generic;
using DWD.Data;
using UnityEngine;

namespace DWD.Core
{
    public class GameManager : MonoBehaviour
    {
        public BalancingConfig Config;

        public EconomyController Economy { get; private set; }
        public RepManager Rep { get; private set; }
        public WarrantyLedger Warranties { get; private set; }
        public LegalEventManager Legal { get; private set; }
        public LoanManager Loans { get; private set; }

        public int CurrentDay { get; private set; }
        public GameStage CurrentStage { get; private set; }
        public List<CarData> Inventory { get; private set; } = new();
        public List<CarData> CurrentListings { get; private set; } = new();
        public List<BuyerOffer> CurrentOffers { get; private set; } = new();
        public bool IsGameOver { get; private set; }
        public string GameOverReason { get; private set; }
        public bool IsPaused { get; set; }

        public ToolkitLevel PlayerToolkit = ToolkitLevel.None;

        private float _dayTimer;

        public event Action<int> OnDayAdvanced;
        public event Action<string> OnGameEvent;
        public event Action<string> OnGameOver;

        public void InitializeGame()
        {
            Economy = GetComponent<EconomyController>();
            Rep = GetComponent<RepManager>();
            Warranties = GetComponent<WarrantyLedger>();
            Legal = GetComponent<LegalEventManager>();
            Loans = GetComponent<LoanManager>();

            Economy.Initialize(Config);
            Rep.Initialize(Config);
            Warranties.Initialize(Config);
            Legal.Initialize(Config);
            Loans.Initialize(Config);

            CurrentDay = 1;
            CurrentStage = GameStage.Driveway;
            Inventory.Clear();
            CurrentListings.Clear();
            CurrentOffers.Clear();
            IsGameOver = false;
            GameOverReason = null;
            _dayTimer = 0f;
        }

        private void Update()
        {
            if (IsGameOver || IsPaused) return;
            _dayTimer += Time.deltaTime;
            if (_dayTimer >= Config.DayLengthSeconds)
            {
                _dayTimer = 0f;
                AdvanceDay();
            }
        }

        public void AdvanceDay()
        {
            CurrentDay++;

            // Process economy
            Economy.ProcessDay();

            // Process loans
            var loanEvents = Loans.ProcessDay(CurrentDay, Rep.QualifiesForInterestDiscount);
            foreach (var e in loanEvents)
            {
                Rep.AdjustRep(Config.RepMissedLoanPayment, "Missed loan payment");
                OnGameEvent?.Invoke(e);
            }

            // Process warranties
            var claims = Warranties.ProcessDay(CurrentDay);
            foreach (var claim in claims)
            {
                if (Economy.CanAfford(claim.RepairCost))
                {
                    Economy.DeductCash(claim.RepairCost, $"Warranty claim: {claim.CarDescription}");
                    Rep.AdjustRep(Config.RepWarrantyClaimPaid, "Warranty claim (paid)");
                    OnGameEvent?.Invoke($"Warranty claim on {claim.CarDescription}: paid ${claim.RepairCost}");
                }
                else
                {
                    Rep.AdjustRep(Config.RepWarrantyClaimUnpaid, "Warranty claim (unpaid)");
                    Legal.HandleUnpaidClaim(claim.RepairCost, CurrentDay);
                    OnGameEvent?.Invoke($"CANNOT PAY warranty claim on {claim.CarDescription}! Legal event triggered.");
                }
            }

            // Check legal blacklist
            if (Legal.IsBlacklisted(CurrentDay))
            {
                IsGameOver = true;
                GameOverReason = "BLACKLISTED: Unresolved lawsuit. No buyers, no sellers.";
                OnGameOver?.Invoke(GameOverReason);
                return;
            }

            // Check rep blacklist
            if (Rep.IsBlacklisted)
            {
                IsGameOver = true;
                GameOverReason = "BLACKLISTED: Reputation dropped below 10%.";
                OnGameOver?.Invoke(GameOverReason);
                return;
            }

            // Check bankruptcy
            if (Economy.IsBankrupt)
            {
                IsGameOver = true;
                GameOverReason = "BANKRUPT: Negative cash for 30 consecutive days.";
                OnGameOver?.Invoke(GameOverReason);
                return;
            }

            // Generate new listings
            CurrentListings = ListingGenerator.GenerateListings(CurrentStage, Rep.Rep, Config);

            // Generate buyer offers for listed cars
            CurrentOffers.Clear();
            foreach (var car in Inventory)
            {
                if (!car.IsListed || car.IsSold) continue;
                if (Legal.IsSalesFrozen(CurrentDay)) continue;
                var offer = BuyerGenerator.TryGenerateOffer(car, Rep.Rep, Config, CurrentDay);
                if (offer != null)
                {
                    CurrentOffers.Add(offer);
                    OnGameEvent?.Invoke($"Offer received: ${offer.OfferPrice} for {car.Make}");
                }
            }

            OnDayAdvanced?.Invoke(CurrentDay);
        }

        public bool BuyCar(int listingIndex)
        {
            if (listingIndex < 0 || listingIndex >= CurrentListings.Count) return false;
            var car = CurrentListings[listingIndex];
            if (!Economy.CanAfford(car.PurchasePrice)) return false;
            if (Inventory.Count >= Config.GetStageCapacity(CurrentStage)) return false;

            Economy.DeductCash(car.PurchasePrice, $"Bought {car.Make} ({car.Tier})");
            Inventory.Add(car);
            CurrentListings.RemoveAt(listingIndex);
            OnGameEvent?.Invoke($"Bought {car.Make} for ${car.PurchasePrice}. Mechanical: {car.OverallMechanical:F2}, Aesthetic: {car.Aesthetic:F2}");
            return true;
        }

        public RepairResult RepairCar(int inventoryIndex, ComponentType component, RepairMethod method)
        {
            var car = Inventory[inventoryIndex];
            var result = RepairShop.AttemptRepair(car, component, method, PlayerToolkit, Config);
            Economy.DeductCash(result.Cost, $"Repair {component} on {car.Make}");
            OnGameEvent?.Invoke(result.Description);
            return result;
        }

        public void DetailCar(int inventoryIndex)
        {
            var car = Inventory[inventoryIndex];
            float boost = car.Aesthetic < 0.65f ? Config.DetailPassOne
                : car.Aesthetic < 0.85f ? Config.DetailPassTwo
                : car.Aesthetic < 0.95f ? Config.DetailPassThree
                : 0f;
            car.Aesthetic = Mathf.Min(1f, car.Aesthetic + boost);
            OnGameEvent?.Invoke($"Detailed {car.Make}. Aesthetic: {car.Aesthetic:F2} (+{boost:F2})");
        }

        public void ListCarForSale(int inventoryIndex, int price, WarrantyType warranty)
        {
            var car = Inventory[inventoryIndex];
            car.ListedPrice = price;
            car.IsListed = true;
            car.WarrantyType = warranty;

            // Deduct 3rd party warranty cost
            int warrantyCost = warranty switch
            {
                WarrantyType.ThirdPartyBasic => Config.ThirdPartyBasicCost,
                WarrantyType.ThirdPartyPremium => Config.ThirdPartyPremiumCost,
                _ => 0
            };
            if (warrantyCost > 0)
                Economy.DeductCash(warrantyCost, $"3rd-party warranty for {car.Make}");

            OnGameEvent?.Invoke($"Listed {car.Make} for ${price} with {warranty} warranty");
        }

        public void AcceptOffer(CarData car, BuyerOffer offer)
        {
            car.IsSold = true;
            car.SoldPrice = offer.OfferPrice;
            car.SoldOnDay = CurrentDay;

            Economy.AddCash(offer.OfferPrice, $"Sold {car.Make}");
            Rep.AdjustRep(Config.RepCleanSale, "Clean sale");

            // Register warranty
            int warrantyDays = car.WarrantyType switch
            {
                WarrantyType.ThirdPartyBasic => Config.ThirdPartyBasicDays,
                WarrantyType.ThirdPartyPremium => Config.ThirdPartyPremiumDays,
                WarrantyType.SelfFundedStandard => Config.SelfFundedStandardDays,
                WarrantyType.SelfFundedPremium => Config.SelfFundedPremiumDays,
                _ => 0
            };

            if (warrantyDays > 0)
            {
                float repBonus = car.WarrantyType switch
                {
                    WarrantyType.ThirdPartyBasic => 2f,
                    WarrantyType.ThirdPartyPremium => 4f,
                    WarrantyType.SelfFundedStandard => 5f,
                    WarrantyType.SelfFundedPremium => 8f,
                    _ => 0f
                };
                Rep.AdjustRep(repBonus, $"Sale with {car.WarrantyType} warranty");

                Warranties.AddWarranty(new WarrantyRecord
                {
                    CarId = car.Id,
                    CarDescription = car.Make,
                    Type = car.WarrantyType,
                    DurationDays = warrantyDays,
                    ExpiresOnDay = CurrentDay + warrantyDays,
                    CarReliability = car.OverallReliability,
                    EstimatedClaimCost = (int)(car.SoldPrice * 0.3f)
                });
            }

            Inventory.Remove(car);
            CurrentOffers.RemoveAll(o => o.CarId == car.Id);
            OnGameEvent?.Invoke($"SOLD {car.Make} for ${offer.OfferPrice}! Profit: ${offer.OfferPrice - car.PurchasePrice}");
        }

        public void TakeLoan(int loanType)
        {
            int amount = loanType switch
            {
                0 => Loans.TakeStarterLoan(CurrentDay),
                1 => Loans.TakeYardLoan(CurrentDay),
                2 => Loans.TakeShowroomLoan(CurrentDay),
                _ => 0
            };
            if (amount > 0)
                Economy.AddCash(amount, $"Loan received");
        }
    }
}
